/**
 * PDF 생성 서비스 — html2canvas + jsPDF
 * 한글 지원: DOM 렌더링 → 이미지 캡처 → PDF 삽입
 */
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface PdfOptions {
  filename: string;
  orientation?: 'landscape' | 'portrait';
  margin?: number; // mm
}

/**
 * DOM 요소를 A4 PDF로 변환
 * @param element - 캡처할 DOM 요소
 * @param options - PDF 옵션
 */
export async function generatePdfFromElement(
  element: HTMLElement,
  options: PdfOptions
): Promise<Blob> {
  const { filename, orientation = 'landscape', margin = 10 } = options;

  // A4 크기 (mm)
  const a4Width = orientation === 'landscape' ? 297 : 210;
  const a4Height = orientation === 'landscape' ? 210 : 297;
  const contentWidth = a4Width - margin * 2;
  const contentHeight = a4Height - margin * 2;

  // 인원수에 따라 스케일 조정 (더 선명하게)
  const scale = 2;

  const canvas = await html2canvas(element, {
    scale,
    useCORS: true,
    logging: false,
    backgroundColor: '#ffffff',
  });

  const imgWidth = canvas.width;
  const imgHeight = canvas.height;

  // PDF 생성
  const pdf = new jsPDF({ orientation, unit: 'mm', format: 'a4' });

  // 이미지를 contentWidth에 맞추고, 높이가 넘으면 페이지 분할
  const ratio = contentWidth / (imgWidth / scale);
  const scaledHeight = (imgHeight / scale) * ratio;

  if (scaledHeight <= contentHeight) {
    // 1페이지에 들어감
    pdf.addImage(canvas.toDataURL('image/png'), 'PNG', margin, margin, contentWidth, scaledHeight);
  } else {
    // 여러 페이지
    const pageImgHeight = contentHeight / ratio * scale; // 페이지당 캔버스 높이 (px)
    let yOffset = 0;
    let pageNum = 0;

    while (yOffset < imgHeight) {
      if (pageNum > 0) pdf.addPage();

      // 캔버스의 해당 영역을 잘라서 새 캔버스 생성
      const sliceHeight = Math.min(pageImgHeight, imgHeight - yOffset);
      const pageCanvas = document.createElement('canvas');
      pageCanvas.width = imgWidth;
      pageCanvas.height = sliceHeight;
      const ctx = pageCanvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(canvas, 0, -yOffset);
      }

      const sliceScaledHeight = (sliceHeight / scale) * ratio;
      pdf.addImage(pageCanvas.toDataURL('image/png'), 'PNG', margin, margin, contentWidth, sliceScaledHeight);

      yOffset += pageImgHeight;
      pageNum++;

      // 최대 3페이지
      if (pageNum >= 3) break;
    }
  }

  return pdf.output('blob');
}

/**
 * DOM 요소를 PDF 파일로 다운로드
 */
export async function downloadPdfFromElement(
  element: HTMLElement,
  options: PdfOptions
): Promise<void> {
  const blob = await generatePdfFromElement(element, options);
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = options.filename;
  a.click();
  URL.revokeObjectURL(url);
}

/**
 * DOM 요소를 PDF Blob으로 반환 (ZIP용)
 */
export async function getPdfBlob(
  element: HTMLElement,
  options: PdfOptions
): Promise<Blob> {
  return generatePdfFromElement(element, options);
}
